from microbit import *
import random

aukera = ['Harria', 'Papera', 'Guraizeak']

while True:
    jokalaria = None
    if button_a.is_pressed() and button_b.is_pressed():
        jokalaria = 2   # Guraizeak
    elif button_a.is_pressed():
        jokalaria = 0   # Harria
    elif button_b.is_pressed():
        jokalaria = 1   # Papera

    if jokalaria is not None:
        makina = random.randint(0, 2)
        display.scroll(aukera[jokalaria])
        if jokalaria == makina:
            display.scroll('Berdinketa!')
        elif (jokalaria - makina) % 3 == 1:
            display.scroll('IRABAZI DUZU!')
        else:
            display.scroll('Galdu duzu...')
    sleep(200)

