# ESTAZIO METEOROLOGIKOA — 2. maila
from microbit import *

irakurketak = []

def temp_kalibratua():
    return temperature() - 3

def batez_bestekoa(zerrenda):
    if len(zerrenda) == 0: return 0
    return sum(zerrenda) / len(zerrenda)

def erregistratu():
    t = temp_kalibratua()
    irakurketak.append(t)
    if len(irakurketak) > 10: irakurketak.pop(0)
    return t

def stats_erakutsi():
    if not irakurketak:
        display.scroll('Daturik gabe'); return
    display.scroll('B.B.:' + str(round(batez_bestekoa(irakurketak), 1)))
    display.scroll('Max:' + str(max(irakurketak)))
    display.scroll('Min:' + str(min(irakurketak)))

while True:
    t = erregistratu()
    display.scroll(str(t) + 'C', delay=70)
    if button_a.was_pressed(): stats_erakutsi()
    sleep(5000)

