# Botoi erraldoiak pinekin
from microbit import *

# 0 eta 1 pinak sarrera gisa (botoiak)
# 0 pina GNDra konektatu botoi HANDIA sakatzeko (adibidez: pintza 0 pinera, bestea GND/P0ra)
# 1 pina GNDra konektatu botoi HANDIA sakatzeko (adibidez: pintza 1 pinera, bestea GND/P1era)

while True:
    if pin0.is_touched(): # Pin-a GNDra konektatuta dagoen detektatzen du (sakatuta)
        display.show(Image.YES)
    elif pin1.is_touched():
        display.show(Image.NO)
    else:
        display.clear()
    sleep(50)
